def matrix_score(nums):
    score = 0
    # Sort each row in descending order so we can easily pick the largest remaining
    for row in nums:
        row.sort(reverse=True)

    # Process columns one by one
    for col in range(len(nums[0])):
        max_in_col = 0
        for row in nums:
            if row[col] > max_in_col:
                max_in_col = row[col]
        score += max_in_col

    return score
